import React from 'react';
import { BrowserRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import Login from './pages/Login';
import Home from './pages/Home';
import Clientes from './pages/Clientes';
import Categorias from './pages/Categorias';
import NovaOS from './pages/NovaOS';
import Relatorios from './pages/Relatorios';
import DetalhesOS from './pages/DetalhesOS';
import EditarOS from './pages/EditarOS';

function NavBar() {
    const location = useLocation();
    const { user, logout } = useAuth();
    const [menuOpen, setMenuOpen] = React.useState(false);
    const toggleMenu = () => setMenuOpen(!menuOpen);

    return (
        <nav className="navbar">
            <Link to="/" className="logo">MWR SISTEMA</Link>
            <div className="menu-icon" onClick={toggleMenu}>☰</div>
            <div className={`nav-links ${menuOpen ? 'open' : ''}`}>
                <NavLink to="/" label="🏠 Home" location={location} />
                <NavLink to="/clientes" label="👥 Clientes" location={location} />
                <NavLink to="/categorias" label="📂 Categorias" location={location} />
                <NavLink to="/nova-os" label="➕ Nova OS" location={location} />
                <NavLink to="/relatorios" label="📊 Relatórios" location={location} />
                <button onClick={logout} className="btn btn-secondary" style={{ marginLeft: 'auto', padding: '0.3rem 1rem' }}>Sair</button>
            </div>
        </nav>
    );
}

function NavLink({ to, label, location }) {
    const isActive = location.pathname === to;
    return (
        <Link to={to} className={`nav-link ${isActive ? 'active' : ''}`}>
            {label}
        </Link>
    );
}

function AppRoutes() {
    const { user } = useAuth();
    if (!user) return null;
    return (
        <>
            <NavBar />
            <div style={{ padding: '1rem', maxWidth: '1400px', margin: '0 auto' }}>
                <Routes>
                    <Route path="/" element={<Home />} />
                    <Route path="/clientes" element={<Clientes />} />
                    <Route path="/categorias" element={<Categorias />} />
                    <Route path="/nova-os" element={<NovaOS />} />
                    <Route path="/relatorios" element={<Relatorios />} />
                    <Route path="/os/:id" element={<DetalhesOS />} />
                    <Route path="/os/editar/:id" element={<EditarOS />} />
                </Routes>
            </div>
        </>
    );
}

function App() {
    return (
        <BrowserRouter>
            <AuthProvider>
                <Routes>
                    <Route path="/login" element={<Login />} />
                    <Route path="/*" element={
                        <ProtectedRoute>
                            <AppRoutes />
                        </ProtectedRoute>
                    } />
                </Routes>
            </AuthProvider>
        </BrowserRouter>
    );
}

export default App;
